var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"기상청은 오늘 돌발적으로 내리기 시작한 집중호우가 내일까지 이어질 것이라고 밝혔습니다.","JPN":"気象庁の発表によりますと、本日突発的に降り出した集中豪雨は明日まで続く見込みです。","ENG":"According to the meteorological administration, the heavy downpours that began unexpectedly today will continue into tomorrow.","TWN":"氣象局今天發布局部豪雨特報，這一波雨勢預計會持續至明天。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"저녁 내내 천둥, 번개를 동반한 비바람이 몰아칠 것으로 예상되오니 주무시기 전에…….","JPN":"夜には雷を伴った暴風雨が予想されますので、お休み前には……","ENG":"Rain and wind are expected throughout the evening, along with thunder and lightning, so we urge you t-","TWN":"入夜後預計風雨將伴隨閃電而至，入睡前請……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"의무관은…… 없나?","JPN":"医務官は……留守か？","ENG":"The medic... is on a break, I suppose.","TWN":"醫務官……人呢？"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"오히려 다행이라면 다행이군.","JPN":"むしろ幸いというべきかな。","ENG":"Perhaps it is for the best.","TWN":"希望是我多心了。"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_GIRL","text":{"KOREA":"……음.","JPN":"……うむ。","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"LAB_02","slots":{"L":null,"C":{"char_id":"DAUGHTER_EXTRA_NULL_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_GIRL","text":{"KOREA":"우으……?","JPN":"うう……？","ENG":"Hmm?","TWN":"呃呃……？"},"stage":{"bg":"LAB_02","slots":{"L":null,"C":{"char_id":"DAUGHTER_EXTRA_NULL_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"오랜만이에요. 여전히 연기에 몰두하고 있군요.","JPN":"お久しぶりです。相変わらず芝居熱心ですね。","ENG":"Long time no see. Still pretending, are you?","TWN":"好久不見，你還是演得很認真呢。"},"stage":{"bg":"LAB_02","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"하지만 이미 충분히 조사하고 왔어요. 시간이 없으니 단도직입적으로 묻겠습니다.","JPN":"ですが、もう十分調査してきました。時間がないので単刀直入に聞きます。","ENG":"However, I have done my research. I do not have time, so I will ask you directly.","TWN":"不過我是充分調查過後才來的，時間不多，我就直接發問。"},"stage":{"bg":"LAB_02","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"당신은…… <color=#ffd34c>누구</color>입니까?","JPN":"あなたは……<color=#ffd34c>誰</color>ですか？","ENG":"Who... are <color=#ffd34c>you</color>?","TWN":"你……<color=#ffd34c>是誰</color>？"},"stage":{"bg":"LAB_02","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_GIRL","text":{"KOREA":"……아. ……으음.","JPN":"……あ。……うう。","ENG":"Ah... Mm...","TWN":"……啊……嗯。"},"stage":{"bg":"LAB_02","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"대답하기 싫다면 질문을 바꾸죠.","JPN":"答えたくなければ、質問を変えましょう。","ENG":"If you do not wish to answer, allow me to change the question.","TWN":"不想回答的話，那我換個問題。"},"stage":{"bg":"LAB_02","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그릇으로서 당신의 육신이 품고 있는 그것은 <color=#ffd34c>무엇</color>입니까?","JPN":"器としてのあなたが持っているそれは<color=#ffd34c>何</color>ですか？","ENG":"<color=#ffd34c>What</color> is it within you that is using you as a vessel?","TWN":"身為一個器皿，你懷裡抱著的是<color=#ffd34c>什麼</color>東西？"},"stage":{"bg":"LAB_02","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_GIRL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LAB_02","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"여전히 대답할 생각이 없나 보군요. 당신도. 당신 안에 있는 무언가도.","JPN":"相変わらず答える気はないようですね。あなたも。あなたの中にいる何かも。","ENG":"Still not thinking about answering, I see. You nor the thing inside you.","TWN":"關於你的身分和你懷裡的東西，你都不願意回答嗎？"},"stage":{"bg":"LAB_02","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"좋습니다. 그럼 제 방식대로 읽어내 드리죠.","JPN":"いいでしょう。それでは私のやり方で読ませていただきます。","ENG":"Very well, then I shall read you my way.","TWN":"很好，那我就照我的方式讀囉。"},"stage":{"bg":"LAB_02","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"대정화 전쟁 이후, 관리 거부 구역에서 집행됐던 성무들의 보고서를 모두 열람해 봤습니다.","JPN":"大浄化戦争以後、管理拒否区域で執行された聖務の報告書をすべて閲覧してみました。","ENG":"After the Grand Purification War, I have read every single report of the sacred missions carried out in the Anti-Administration Zone.","TWN":"我已經讀完淨化之戰之後，在拒絕管理區域執行過的聖務相關報告。"},"stage":{"bg":"DOCUMENTS","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};